private void copyAttributes(org.jsoup.nodes.Node source, Element el) {
    for (Attribute attribute : source.attributes()) {
        String key = attribute.getKey();
        // Replace invalid starting characters with prefix 'attr_' to ensure valid XML names
        if (!key.matches("^[a-zA-Z_:].*")) {
            key = "attr_" + key;
        }
        // Replace non-valid characters within the key
        key = key.replaceAll("[^-a-zA-Z0-9_:.]", "_");
        // Ensure the key is unique within the element
        String originalKey = key;
        int counter = 1;
        while (el.hasAttribute(key)) {
            key = originalKey + "_" + counter++;
        }
        el.setAttribute(key, attribute.getValue());
    }
}

